-- DEMO MATCH COMPLETION — run once in Supabase SQL editor
delete from sports_live_scores where match_id='d8800be2-4483-41d0-97b6-77c3d678713d' and innings=2;

-- resolve the two camera estimates: earliest = CONFIRMED, next = REJECTED (human-in-loop showcase)
update sports_tracked_events set estimate=false,
  data_json = coalesce(data_json,'{}'::jsonb) || '{"resolved":"confirmed","resolved_by":"official-demo","resolved_at":"2026-07-16T12:00:00Z"}'::jsonb
where id = (select id from sports_tracked_events where match_id='d8800be2-4483-41d0-97b6-77c3d678713d' order by created_at asc limit 1);
update sports_tracked_events set estimate=false,
  data_json = coalesce(data_json,'{}'::jsonb) || '{"resolved":"rejected","resolved_by":"official-demo","resolved_at":"2026-07-16T12:01:00Z"}'::jsonb
where id = (select id from sports_tracked_events where match_id='d8800be2-4483-41d0-97b6-77c3d678713d' and (data_json->>'resolved') is null order by created_at asc limit 1);

-- close the match (feed computes: chasing side won by 7 wickets + POTM)
update sports_matches set status='completed', result='completed' where id='d8800be2-4483-41d0-97b6-77c3d678713d';
